Greedy best-insertion with feasibility check and fallback to empty assign creation for each unplaced order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    shipID := total_ship
    for i := range oris {
        bestIdx := -1
        bestDelta := math.MaxFloat64
        originalCosts := make([]float64, dispatch.AssignsLen)
        for idx := 0; idx < dispatch.AssignsLen; idx++ {
            originalCosts[idx] = dispatch.Assigns[idx].Cost
            if dispatch.Assigns[idx].AddShip(shipID+i, oris[i], dess[i]) {
                dispatch.Assigns[idx].GenRoute()
                if dispatch.Assigns[idx].Cost >= 0 {
                    delta := dispatch.Assigns[idx].Cost - originalCosts[idx]
                    if delta < bestDelta {
                        bestDelta = delta
                        bestIdx = idx
                    }
                }
                dispatch.Assigns[idx].RemoveShip(shipID + i)
                dispatch.Assigns[idx].Cost = originalCosts[idx]
                dispatch.Assigns[idx].GenRoute()
            }
        }
        if bestIdx >= 0 {
            dispatch.Assigns[bestIdx].AddShip(shipID+i, oris[i], dess[i])
            dispatch.Assigns[bestIdx].GenRoute()
        } else {
            if dispatch.AssignsLen < MAXASSIGNS {
                dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID+i, oris[i], dess[i])
                dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
                    dispatch.AssignsLen++
                } else {
                    dispatch.Assigns[dispatch.AssignsLen].RemoveShip(shipID + i)
                    dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

